import xml.etree.ElementTree as ET
import os, sys

errors = []
for root, dirs, files in os.walk('/testbed/src/SamplesApp'):
    for f in files:
        if f.endswith('.xaml'):
            fp = os.path.join(root, f)
            try:
                ET.parse(fp)
            except ET.ParseError as e:
                errors.append((fp, str(e)))

if errors:
    print(f'{len(errors)} files have XML parse errors:')
    for fp, err in errors:
        print(f'  {fp}: {err}')
    sys.exit(1)
else:
    print('All XAML files are well-formed XML.')
